tool_calls:
tmp=$(mktemp)
{
  IFS= read -r first < /doc/README.md
  printf '%s\n\n' "$first"
  grep -E '^#{1,2} ' /doc/README.md | while IFS= read -r line; do
    text=${line#\# }
    text=${text#\#\# }
    anchor=${text,,}
    anchor=${anchor// /-}
    printf -- '- [%s](#%s)\n' "$text" "$anchor"
  done
  tail -n +2 /doc/README.md
} > "$tmp"
mv "$tmp" /doc/README.md
cat /doc/README.md

grep -E '^#{1,2} ' /doc/README.md | while IFS= read -r line; do
  text=${line#\# }
  text=${text#\#\# }
  anchor=${text,,}
  anchor=${anchor// /-}
  declare -p line text anchor
  printf '%s\n' "- [$text](#$anchor)"
done

tmp=$(mktemp)
{
  IFS= read -r first < /doc/README.md
  printf '%s\n\n' "$first"
  grep -E '^#{1,2} ' /doc/README.md | while IFS= read -r line; do
    case "$line" in
      '## '*) text=${line#'## '} ;;
      '# '*) text=${line#'# '} ;;
      *) continue ;;
    esac
    anchor=${text,,}
    anchor=${anchor// /-}
    printf '%s\n' "- [$text](#$anchor)"
  done
  printf '\n'
  tail -n +2 /doc/README.md | sed '/^- \[/d' | sed '1{/^$/d;}'
} > "$tmp"
mv "$tmp" /doc/README.md
cat /doc/README.md

